flutter/flutter#183378.body:
### Steps to reproduce

1. Run the sample code.
2. Press "Validate" to trigger validation errors.

### Expected results

Using `errorBuilder` alongside `decoration: InputDecoration(errorText: ...)` should work — the `errorBuilder` widget should replace the decoration's `errorText` when validation triggers.

### Actual results

The app crashes with:
```
Declaring both error and errorText is not supported.
```

Without `errorBuilder` (added at PR [#162255](https://github.com/flutter/flutter/pull/162255)), the `errorText` path only calls `copyWith(errorText: field.errorText)` with a non-null value — which works fine. But `errorBuilder` introduced a code path that needs to *clear* `errorText` via `copyWith(errorText: null)` to replace it with an `error` widget, and `InputDecoration.copyWith` silently ignores `null` (treats it as "keep existing value"). This leaves both `error` and `errorText` set on the decoration, triggering the assertion.

i.e in `DropdownButtonFormField`, `errorBuilder` tries to clear `errorText` and use `error` instead, but `copyWith` ignores it:
```dart
// dropdown.dart
final Widget? error =
    field.errorText != null && errorBuilder != null
        ? errorBuilder(state.context, field.errorText!)
        : null;
final String? errorText = error == null ? field.errorText : null;

effectiveDecoration = effectiveDecoration.copyWith(
  error: error,
  errorText: errorText, // null when errorBuilder is used — copyWith ignores it
  hintText: hintText,
);
```

### Code sample

<details open><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: Scaffold(
        appBar: AppBar(title: const Text('errorBuilder copyWith Bug')),
        body: Center(
          child: Padding(
            padding: const EdgeInsets.all(32),
            child: Form(
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  TextFormField(
                    decoration: const InputDecoration(
                      labelText: 'TextFormField',
                      errorText: 'Decoration error',
                    ),
                    errorBuilder: (context, error) {
                      return Row(
                        children: [
                          const Icon(Icons.error, color: Colors.red, size: 16),
                          const SizedBox(width: 4),
                          Text(error, style: const TextStyle(color: Colors.red, fontSize: 12)),
                        ],
                      );
                    },
                    validator: (value) => value!.isEmpty ? 'Field is required' : null,
                  ),
                  const SizedBox(height: 24),
                  DropdownButtonFormField<String>(
                    decoration: const InputDecoration(
                      hintText: 'Select an option',
                      errorText: 'Decoration error',
                    ),
                    errorBuilder: (context, error) {
                      return Row(
                        children: [
                          const Icon(Icons.error, color: Colors.red, size: 16),
                          const SizedBox(width: 4),
                          Text(error, style: const TextStyle(color: Colors.red, fontSize: 12)),
                        ],
                      );
                    },
                    items: const [
                      DropdownMenuItem(value: 'one', child: Text('One')),
                      DropdownMenuItem(value: 'two', child: Text('Two')),
                    ],
                    validator: (value) => value == null ? 'Selection required' : null,
                    onChanged: (value) {},
                  ),
                  const SizedBox(height: 24),
                  Builder(
                    builder: (context) => ElevatedButton(
                      onPressed: () => Form.of(context).validate(),
                      child: const Text('Validate'),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }
}
